const toDeterministicUuid = (value) => {
  const hex = String(value || '').toLowerCase().replace(/[^0-9a-f]/g, '');
  const padded = (hex + '00000000000000000000000000000000').slice(0, 32);
  return `${padded.slice(0, 8)}-${padded.slice(8, 12)}-${padded.slice(12, 16)}-${padded.slice(16, 20)}-${padded.slice(20, 32)}`;
};

const vaultWriteStatus = String($json.vault_write_status || $json.vault_write || '').trim();
const qdrantBaseUrl = String($json.qdrant_base_url || 'http://qdrant:6333').trim().replace(/\/*$/, '');
const qdrantCollection = String($json.qdrant_collection || '').trim();
const embedding = Array.isArray($json.embedding) ? $json.embedding : [];
const shouldCommitQdrant = vaultWriteStatus === 'written'
  && Boolean($json.should_upsert_qdrant)
  && qdrantBaseUrl
  && qdrantCollection
  && embedding.length > 0;
const qdrantPointId = String($json.qdrant_point_id || '').trim() || toDeterministicUuid($json.item_id);

return {
  json: {
    ...$json,
    qdrant_point_id: qdrantPointId,
    qdrant_upsert_endpoint: shouldCommitQdrant
      ? `${qdrantBaseUrl}/collections/${encodeURIComponent(qdrantCollection)}/points`
      : String($json.qdrant_upsert_endpoint || '').trim(),
    qdrant_upsert_payload: shouldCommitQdrant
      ? {
          points: [
            {
              id: qdrantPointId,
              vector: embedding,
              payload: {
                item_id: $json.item_id,
                source_type: $json.source_type,
                source_name: $json.source_name,
                title: $json.title,
                canonical_url: $json.canonical_url,
                published_at: $json.published_at,
                score: $json.score,
                category: $json.category,
                summary: $json.summary,
                dedupe_action: $json.dedupe_action,
                matched_score: $json.matched_score,
                tags: $json.tags,
                content_hash: $json.content_hash
              }
            }
          ]
        }
      : ($json.qdrant_upsert_payload ?? null),
    should_commit_qdrant: shouldCommitQdrant,
    qdrant_operation: shouldCommitQdrant ? 'pending' : 'skipped',
    qdrant_upsert_response: shouldCommitQdrant ? null : ($json.qdrant_upsert_response ?? null)
  }
};

const original = $('Build Qdrant Commit Payload').item.json || {};
return {
  json: {
    ...original,
    qdrant_operation: 'upserted',
    qdrant_upsert_response: $json
  }
};

return {
  json: {
    ...$json,
    qdrant_operation: String($json.qdrant_operation || 'skipped').trim() || 'skipped',
    qdrant_upsert_response: $json.qdrant_upsert_response ?? null
  }
};

return {
  json: {
    ...$json,
    qdrant_operation: String($json.qdrant_operation || 'skipped').trim() || 'skipped',
    qdrant_upsert_response: $json.qdrant_upsert_response ?? null
  }
};
